var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"하아……! 하아……!","JPN":"はあ……！　はあ……！","ENG":"*Huff…!* *Huff…!*","TWN":"呼呼……！呼呼……！"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CULTIST_VATICAN_SUPPLEMENT_NPC","text":{"KOREA":"멈추어라, 불 <color=#ff3636>타오르는 어</color>린 양! 침몰<color=#ff3636> 당하는 부모</color>님을 위<b>하</b>여……!","JPN":"止まれ、燃<color=#ff3636>え上がる子</color>羊よ！　沈没<color=#ff3636>する両</color>親のた<b>め</b>に……！","ENG":"Stop, y<color=#ff3636>ou burnin</color>g young lamb! For <color=#ff3636>the sinking</color> par<b>ent</b>s...!","TWN":"止住吧，燃<color=#ff3636>燒的小</color>羊！為衰敗<color=#ff3636>的</color>父<b>母</b>親……！"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_VATICAN_SUPPLEMENT_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"하아, 하아…… 머리가 아파. 몸이 뜨거워…….","JPN":"はあ、はあ……頭が痛い。体が熱い……","ENG":"*Huff...* *Huff...* My head is throbbing, and my body feels as if it’s on fire...","TWN":"呼呼呼……我的頭好痛，身體好燙……"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"이제, 더 이상은…….","JPN":"もう、これ以上は……","ENG":"I can no longer...","TWN":"我不行了……"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"AGNES_VATICAN_SUPPLEMENT_QM","text":{"KOREA":"뭐야? 뭐가 문젠데 그렇게 쩔쩔 매고 있어?","JPN":"何？　そんなに慌ててどうしたんだよ？","ENG":"Huh? What's the matter, and why are you so flustered?","TWN":"怎麼搞的？怎麼會搞得這麼落魄？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"이 목소리는?","JPN":"この声は？","ENG":"That voice...","TWN":"這個聲音是？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"저 쪼다들이 문제야?","JPN":"あの出来損ないのやつらのせいなのか？","ENG":"Are those losers the problem?","TWN":"是那些傢伙害的嗎？"},"stage":{"bg":"UNDER","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_LAUGH"},"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"루퍼 자매님!!","JPN":"シスター・ルーパー！！","ENG":"Sister Looper!!","TWN":"洛珀姊妹！！"},"stage":{"bg":"UNDER","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L17_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"거 몸 상태도 별로 같은데, 천당 가기 싫으면 뒤에서 박수나 치고 있어.","JPN":"具合も悪そうだし、天国に行きたくないなら後ろの方で拍手でもしてて。","ENG":"You don't look so good. Just stand in the corner and clap your hands if you don't wanna go to Heaven.","TWN":"我看你身體狀況也不太好，不想見天主的話，還是在後面拍手就好吧。"},"stage":{"bg":"UNDER","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L18_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"어차피 눈 깜빡할 새면 끝날 테니까.","JPN":"あっという間に終わるから。","ENG":"It'll all be over in a flash.","TWN":"反正瞬間就會結束的。"},"stage":{"bg":"UNDER","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L22_1","type":"dialog","speaker":"CULTIST_VATICAN_SUPPLEMENT_NPC","text":{"KOREA":"멈추어라, 불 <color=#ff3636>타오르는 어</color>린 양! 침몰<color=#ff3636> 당하는 부모</color>님을 위<b>하</b>여……!","JPN":"止まれ、燃<color=#ff3636>え上がる子</color>羊よ！　沈没<color=#ff3636>する両</color>親のた<b>め</b>に……！","ENG":"Stop, y<color=#ff3636>ou burnin</color>g young lamb! For <color=#ff3636>the sinking</color> par<b>ent</b>s...!","TWN":"止住吧，燃<color=#ff3636>燒的小</color>羊！為衰敗<color=#ff3636>的</color>父<b>母</b>親……！"},"stage":{"bg":"UNDER","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_VATICAN_SUPPLEMENT_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"할 얘기 있으면 알아듣게 말해. 그래야 나중에 딴 소리 못하지.","JPN":"話があるならはっきり言ってよね。後で話が違ったとか言わないでさ。","ENG":"If you want to say something, say it loud and clear. So you don't try to get out of it with some bogus excuse later.","TWN":"要說話就好好說！否則以後沒機會說囉！"},"stage":{"bg":"UNDER","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CULTIST_VATICAN_SUPPLEMENT_NPC","text":{"KOREA":"다가<color=#ff3636>올 눈부신 멸</color>망을 위해, 괴상<color=#ff3636>망측한 용</color>서를 <b>빌</b> 지어다……!","JPN":"来る<color=#ff3636>べき輝かしい滅</color>亡のために、奇怪<color=#ff3636>な許</color>しを求<b>め</b>よ……！","ENG":"Pray f<color=#ff3636>or absurd</color> forgiveness, for t<color=#ff3636>he dazzling do</color>om to<b> come</b>......!","TWN":"燦<color=#ff3636>爛的末</color>日將到，祈求<color=#ff3636>詭異的</color>饒<b>恕</b> ……！"},"stage":{"bg":"UNDER","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_VATICAN_SUPPLEMENT_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"아아, 용서가 필요해?","JPN":"ああ、許しがほしい？","ENG":"Oh...! You want forgiveness?","TWN":"喔喔～需要饒恕是嗎？"},"stage":{"bg":"UNDER","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"그래. 뭐 까짓 거 나는 용서하지.","JPN":"そうね。まあ、あたしは許してあげるよ。","ENG":"Yeah, sure. What the heck, I'll give you forgiveness.","TWN":"這簡單，好啦，我饒恕你們！"},"stage":{"bg":"UNDER","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"하지만…… 이 녀석이 용서할까?","JPN":"でも……こいつはどうかな？","ENG":"But... my little friend might beg to differ!","TWN":"不過……它會饒恕你們嗎？"},"stage":{"bg":"UNDER","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_LAUGH"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"야, 꺽다리. 이쪽은 끝났어. 그쪽은 어때?","JPN":"おい、のっぽ。こっちは終わったよ。そっちはどう？","ENG":"Hey, Long Legs, I’m all done over here. How about you?","TWN":"喂，高個子，我這邊結束咧，你那邊呢？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L37_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"그래, 다행이군. 이쪽도 어느정도 마무리가 됐다.","JPN":"そうか、良かったな。こちらも大体片付いた。","ENG":"That is great news. This side is also coming to a close.","TWN":"是嗎？那就好，我這邊也處理得差不多。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"몇 마리가 갑자기 도망치긴 했지만, 시체 대부분은 뿌리 침식체와 연결이 끊긴 것 같다.","JPN":"何匹かは急に逃げ出したが、ほとんどの死体は木の根の侵食体との繋がりが切れたようだ。","ENG":"A few fled, but the majority of the corpses have been disconnected from the root C.O.","TWN":"雖然逃掉幾隻，但大部分的屍體都已經斷開和樹根侵蝕體之間的連結。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"근데, 무슨 소리야?","JPN":"てか、何の音？","ENG":"Okay, but what's that sound?","TWN":"那是什麼聲音？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"죽은 이들을 위해 묘지를 만들어주고 있는 중이었다.","JPN":"死んだ者たちのために墓を作っている。","ENG":"I was digging a cemetery for the dead.","TWN":"我在替這些死去的人挖墳墓。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"이교도들이지만 그들에게도 죽음을 존중받을 가치가 있으니까 말이지.","JPN":"異教徒だが、彼らの死も尊重されなければならないからな。","ENG":"Though they are heretics, they still deserve a proper burial.","TWN":"雖然他們是異端，但他們也該獲得應有的尊重。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"바빠 죽겠는데 가지가지 하네 진짜.","JPN":"忙しいのに呑気だね、まったく。","ENG":"You're gonna waste precious time doing what now?","TWN":"真是的，忙得要死還搞那些有的沒有！"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"}}}},{"id":"L47_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"자, 잠깐만요. 신부님!","JPN":"ま、待ってください。神父様！","ENG":"W-wait Father Constantine!","TWN":"先，先等一下，神父！"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"그 뿌리 같은 침식체라면 지하 수도 안쪽에서 봤어요!","JPN":"あの根のような侵食体でしたら、地下水度の奥で見ましたわ！","ENG":"I saw those root-like C.O.s in the underground waterway!","TWN":"我在地下道裡也有看到那個長得像樹根的侵蝕體！"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"정말인가?","JPN":"本当か？","ENG":"Is that so?","TWN":"真的嗎？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"네. 그리고 저 안에는 저와 같이 있었던 어린 양이…….","JPN":"はい。それにあの中には私と一緒にいた子羊が……","ENG":"Yes. There was also a young lamb down there with me...","TWN":"對，而且那裡面還有另一隻小羊……"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"생존자? 자네 말고도 아직 생존자가 남았단 말인가?","JPN":"生存者？　君以外にもまだ生存者が残っているのか？","ENG":"A survivor? You mean to say there is another survivor besides you?","TWN":"倖存者？你說除了你以外還有其他倖存者？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"말도 안 돼, 이미 잔해가 돼 버렸을……","JPN":"馬鹿な、すでに残骸になっているはず……","ENG":"That cannot be... All should become the Remains...","TWN":"怎麼可能，應該已經變成殘骸……"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"어이, 꺽다리. 뭔 생각을 그렇게 해.","JPN":"おい、のっぽ。何考えこんでるんだよ。","ENG":"Hey Long Legs, whatcha thinkin' about?","TWN":"喂，高個子，你在想什麼？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"생존자라고 하면 뻔하잖아. 마을에서 보이지 않던 아이 중 하나겠지.","JPN":"生存者なら確かめるまでもない。村にはいなかった子どもの一人でしょ。","ENG":"Isn't it obvious who the survivor is? It must be one of the children I couldn't see in the village.","TWN":"這不是很明顯嗎？就是沒在村裡看到的其中一個孩子吧？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"……그래, 그렇겠지.","JPN":"……ああ、そうだろうな。","ENG":"Yes... I suppose you are right.","TWN":"……嗯嗯，應該吧。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"알겠다. 즉시 그쪽으로 가지. 신디와 클로디아는 현장에서 대기하도록.","JPN":"わかった。今すぐそちらに向かおう。シンディとクラウディアはそこで待機したまえ。","ENG":"Understood. I will head down there immediately. Cindy and Claudia, you two stay here and wait for me.","TWN":"好吧，我立刻出發過去，辛蒂和克勞迪婭，你們在現場等候。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};